A company must copy customer account data changes from a Microsoft Dataverse instance into an external system. Azure Storage Queues are used to pass the changes from Dataverse to the external system.

You have the following code. (Line numbers are included for reference only.)

```csharp
01 string token = null;
02 token = ProcessAccountChanges(_service, token, changeQueue, deleteQueue);
03 ...
04 token = ProcessAccountChanges(_service, token, changeQueue, deleteQueue);
05 ...
06 private static string ProcessAccountChanges(IOrganizationService orgservice,
   string token, CloudQueue changeQueue, CloudQueue deleteQueue)
07 {
08   var request = new RetrieveEntityChangesRequest();
09   request.EntityName = "account";
10   request.Columns = new ColumnSet("name", "accountnumber", "creditlimit", "ownerid");
11   request.DataVersion = token;
12   RetrieveEntityChangesResponse response = (RetrieveEntityChangesResponse)orgservice.Execute(request);
13   token = response.EntityChanges.DataToken;
14   foreach (var change in response.EntityChanges.Changes)
15   {
16     if (change.Type == ChangeType.NewOrUpdated)
17     {
18       var changedItem = (NewOrUpdatedItem)change;
19       Entity newOrChangedEntity = (Entity)changedItem.NewOrUpdatedEntity;
20       CloudQueueMessage changemessage = new CloudQueueMessage(newOrChangedEntity.Id.ToString());
21       changeQueue.AddMessage(changemessage);
22     }
23     else if (change.Type == ChangeType.RemoveOrDeleted)
24     {
25       var deleteditem = (RemovedOrDeletedItem)change;
26       EntityReference deletedEntityReference = deleteditem.RemovedItem;
27       CloudQueueMessage deletemessage = new CloudQueueMessage(deletedEntityReference.Id.ToString());
28       deleteQueue.AddMessage(deletemessage);
29     }
30   }
31   return token;
32 }
```

